def modp(n: int, p: int) -> int:
    # Handle edge case where n is 0 or p is 1
    if n == 0 or p == 1:
        return 1

    # Compute the remainder of n divided by p
    remainder = n % p

    # If the remainder is negative, return the result modulo p again
    if remainder < 0:
        return (remainder + p) % p
    else:
        return remainder
